// LÓGICA DO APP
// ═══════════════════════════════════════════
let cart = [], currentItem = null, modalQty = 1, deliveryType = 'delivery';
const MENU_MAP = {};
MENU.forEach(cat => cat.items.forEach(item => { MENU_MAP[item.id] = item; }));

function fmt(v) { return 'R$ ' + v.toFixed(2).replace('.', ','); }

function buildMenu() {
  const nav = document.getElementById('catNav');
  const main = document.getElementById('mainContent');
  nav.innerHTML = ''; main.innerHTML = '';
  MENU.forEach((cat, ci) => {
    const btn = document.createElement('button');
    btn.className = 'cat-btn' + (ci === 0 ? ' active' : '');
    btn.textContent = cat.name; btn.dataset.cat = cat.id;
    btn.onclick = () => document.getElementById('sec-' + cat.id).scrollIntoView({behavior:'smooth',block:'start'});
    nav.appendChild(btn);

    const sec = document.createElement('section');
    sec.id = 'sec-' + cat.id; sec.className = 'cat-section'; sec.dataset.cat = cat.id;
    const title = document.createElement('div');
    title.className = 'section-title'; title.textContent = cat.name;
    sec.appendChild(title);

    const grid = document.createElement('div');
    grid.className = 'product-grid';
    cat.items.forEach(item => {
      const card = document.createElement('div');
      card.className = 'product-card' + (item.available ? '' : ' unavailable') + (item.featured ? ' featured' : '');
      card.dataset.name = (item.name + ' ' + item.desc).toLowerCase();
      card.onclick = () => openModal(item);

      const imgWrap = document.createElement('div');
      imgWrap.className = 'card-img-wrap';
      if (item.featured) {
        const fb = document.createElement('div');
        fb.className = 'featured-badge'; fb.textContent = '⭐ LANCHE DA CASA';
        imgWrap.appendChild(fb);
      }
      const imgEl = document.createElement('div');
      imgEl.className = 'card-img';
      if (item.img) { imgEl.innerHTML = '<img src="' + item.img + '" alt="' + item.name + '" loading="lazy"/>'; }
      else { imgEl.textContent = item.emoji || '🍔'; }
      imgWrap.appendChild(imgEl);
      card.appendChild(imgWrap);

      const body = document.createElement('div');
      body.className = 'card-body';
      body.innerHTML = `
        <div class="card-name">${item.name}</div>
        <div class="card-desc">${item.desc}</div>
        <div class="card-footer">
          <div class="card-price">${fmt(item.price)}</div>
          ${item.available
            ? `<button class="add-btn" onclick="event.stopPropagation();openModal(MENU_MAP['${item.id}'])">+</button>`
            : '<span class="sold-out-badge">Esgotado</span>'}
        </div>`;
      card.appendChild(body);
      grid.appendChild(card);
    });
    sec.appendChild(grid);
    main.appendChild(sec);
  });
}

function setupScrollSpy() {
  const obs = new IntersectionObserver(entries => {
    entries.forEach(e => {
      if (e.isIntersecting) {
        document.querySelectorAll('.cat-btn').forEach(b =>
          b.classList.toggle('active', b.dataset.cat === e.target.dataset.cat));
      }
    });
  }, { rootMargin: '-40% 0px -55% 0px' });
  document.querySelectorAll('.cat-section').forEach(s => obs.observe(s));
}

document.getElementById('searchInput').addEventListener('input', function() {
  const q = this.value.toLowerCase().trim();
  document.querySelectorAll('.product-card').forEach(c => {
    c.classList.toggle('hidden', q && !c.dataset.name.includes(q));
  });
  document.querySelectorAll('.cat-section').forEach(s => {
    const v = [...s.querySelectorAll('.product-card')].some(c => !c.classList.contains('hidden'));
    s.classList.toggle('hidden', !v);
  });
});

function openModal(item) {
  currentItem = item; modalQty = 1;
  document.getElementById('modalQty').textContent = '1';
  document.getElementById('modalName').textContent = item.name;
  document.getElementById('modalDesc').textContent = item.desc;
  document.getElementById('modalPrice').textContent = fmt(item.price);
  document.getElementById('modalObs').value = '';
  updateModalBtn();
  const mi = document.getElementById('modalImg');
  mi.style.padding = '';
  if (item.img) { mi.innerHTML = '<img src="' + item.img + '" alt="' + item.name + '"/>'; }
  else { mi.textContent = item.emoji || '🍔'; mi.style.padding = '28px 0'; mi.style.fontSize = '5rem'; }
  document.getElementById('productModal').classList.add('open');
  document.body.style.overflow = 'hidden';
}

function closeModal() {
  document.getElementById('productModal').classList.remove('open');
  document.body.style.overflow = '';
}

function changeModalQty(d) {
  modalQty = Math.max(1, modalQty + d);
  document.getElementById('modalQty').textContent = modalQty;
  updateModalBtn();
}

function updateModalBtn() {
  if (!currentItem) return;
  const t = (currentItem.price * modalQty).toFixed(2).replace('.', ',');
  document.getElementById('btnAddCart').textContent = `🛒 ADICIONAR · R$ ${t}`;
}

function addToCart() {
  if (!currentItem) return;
  const obs = document.getElementById('modalObs').value.trim();
  const key = currentItem.id + '|' + obs;
  const ex = cart.find(i => i.key === key);
  if (ex) { ex.qty += modalQty; } else { cart.push({key, item:currentItem, qty:modalQty, obs}); }
  closeModal(); updateCartUI();
}

function openCart() {
  document.getElementById('cartOverlay').classList.add('open');
  document.getElementById('cartPanel').classList.add('open');
  document.body.style.overflow = 'hidden';
  renderCartItems();
}

function closeCart() {
  document.getElementById('cartOverlay').classList.remove('open');
  document.getElementById('cartPanel').classList.remove('open');
  document.body.style.overflow = '';
}

function selectDelivery(type) {
  deliveryType = type;
  document.getElementById('optDelivery').classList.toggle('selected', type === 'delivery');
  document.getElementById('optRetirada').classList.toggle('selected', type === 'retirada');
  updateCartTotals();
}

function changeCartQty(key, d) {
  const idx = cart.findIndex(i => i.key === key);
  if (idx < 0) return;
  cart[idx].qty = Math.max(0, cart[idx].qty + d);
  if (cart[idx].qty === 0) cart.splice(idx, 1);
  renderCartItems(); updateCartUI();
}

function renderCartItems() {
  const el = document.getElementById('cartItemsEl');
  if (!cart.length) {
    el.innerHTML = '<div class="empty-cart"><span class="empty-icon">🛒</span><div>Carrinho vazio — adicione seus lanches!</div></div>';
    return;
  }
  el.innerHTML = cart.map(ci => `
    <div class="cart-item">
      <div class="ci-info">
        <div class="ci-name">${ci.item.name}</div>
        ${ci.obs ? '<div class="ci-obs">📝 ' + ci.obs + '</div>' : ''}
        <div class="ci-controls">
          <button class="ci-qty-btn" onclick="changeCartQty('${ci.key}',-1)">−</button>
          <span class="ci-qty">${ci.qty}</span>
          <button class="ci-qty-btn" onclick="changeCartQty('${ci.key}',1)">+</button>
        </div>
      </div>
      <div class="ci-price">${fmt(ci.item.price * ci.qty)}</div>
    </div>`).join('');
  updateCartTotals();
}

function updateCartTotals() {
  const sub = cart.reduce((s,i) => s + i.item.price * i.qty, 0);
  const fee = deliveryType === 'delivery' ? CONFIG.deliveryFee : 0;
  document.getElementById('subtotalEl').textContent = fmt(sub);
  document.getElementById('deliveryFeeEl').textContent = fee ? fmt(fee) : 'Grátis';
  document.getElementById('totalEl').textContent = fmt(sub + fee);
}

function updateCartUI() {
  const count = cart.reduce((s,i) => s + i.qty, 0);
  const sub = cart.reduce((s,i) => s + i.item.price * i.qty, 0);
  document.getElementById('cartFab').classList.toggle('visible', count > 0);
  document.getElementById('fabCount').textContent = count;
  document.getElementById('fabTotal').textContent = fmt(sub);
  if (document.getElementById('cartPanel').classList.contains('open')) updateCartTotals();
}

function sendWhatsApp() {
  if (!cart.length) return;

  // 1. Verifica se já temos os dados do cliente
  const dadosSalvos = localStorage.getItem('clienteCordeiro');
  
  // Se for entrega e não tivermos dados, abre o modal em vez de enviar
  if (deliveryType === 'delivery' && !dadosSalvos) {
    document.getElementById('modal-cliente').style.display = 'flex';
    return; // Interrompe o envio para abrir o modal
  }

  // 2. Monta a mensagem (com os dados do cliente, se existirem)
  const cliente = dadosSalvos ? JSON.parse(dadosSalvos) : null;
  const sub = cart.reduce((s,i) => s + i.item.price * i.qty, 0);
  const fee = deliveryType === 'delivery' ? CONFIG.deliveryFee : 0;
  
  let msg = `*Meu Pedido no Cordeiro & Brasa* 🔥🐑\n\n*Cliente:* ${cliente ? cliente.nome : 'Não informado'}\n*Endereço:* ${cliente ? cliente.endereco : 'Retirada no local'}\n\n*Itens:*\n`;
  
  cart.forEach(ci => {
    msg += `• ${ci.qty}× ${ci.item.name} — ${fmt(ci.item.price * ci.qty)}`;
    if (ci.obs) msg += `\n  _(${ci.obs})_`;
    msg += '\n';
  });

  msg += `\n*Subtotal:* ${fmt(sub)}\n*Entrega:* ${fee ? fmt(fee) : 'Retirada'}\n*TOTAL: ${fmt(sub + fee)}*`;
  msg += `\n\n*Tipo:* ${deliveryType === 'delivery' ? '🚗 Entrega' : '🏃 Retirada'}`;
  msg += `\n\n_Sabor que Alimenta • Fé que Transforma_ 🙏`;

  window.open(`https://wa.me/${CONFIG.whatsappNumber}?text=${encodeURIComponent(msg)}`, '_blank');
}


// --- Função principal que salva e calcula ---
async function salvarDados() {
  const nome = document.getElementById('nome-cliente').value;
  const enderecoInput = document.getElementById('endereco-cliente').value;
  const enderecoCompleto = enderecoInput + ", Suzano - SP";

  if (nome && enderecoInput) {
    try {
      // Usamos a função que você já tem configurada com o cálculo matemático
      const taxa = await calcularTaxaGeografica(enderecoCompleto);
      
      // Salva os dados no navegador
      const dados = { nome, endereco: enderecoCompleto, taxa: taxa };
      localStorage.setItem('clienteCordeiro', JSON.stringify(dados));
      
      // Fecha o modal
      document.getElementById('modal-cliente').style.display = 'none';
      
      // Atualiza o total se a função existir
      if (typeof updateCartTotals === 'function') {
        updateCartTotals(); 
      }
      
      // Segue para o envio
      enviarPedidoWhatsApp(); 
    } catch (e) {
      console.error(e);
      alert("Não conseguimos calcular a distância. Verifique o endereço e tente novamente.");
    }
  } else {
    alert("Por favor, preencha o nome e o endereço.");
  }
}

// --- Função que verifica se o cliente já existe ---
function verificarClienteEEnviar() {
  const dadosSalvos = localStorage.getItem('clienteCordeiro');
  
  if (dadosSalvos) {
    enviarPedidoWhatsApp();
  } else {
    document.getElementById('modal-cliente').style.display = 'flex';
  }
}

// --- Coordenadas da Cordeiro & Brasa (Exatas) ---
const COORD_LOJA = { lat: -23.5413, lon: -46.3151 }; 

async function calcularTaxaGeografica(enderecoCliente) {
    const url = `https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(enderecoCliente)}`;
    const response = await fetch(url);
    const data = await response.json();
    
    if (data.length === 0) throw new Error("Endereço não encontrado");
    
    const latCliente = parseFloat(data[0].lat);
    const lonCliente = parseFloat(data[0].lon);
    
    const R = 6371; 
    const dLat = (latCliente - COORD_LOJA.lat) * Math.PI / 180;
    const dLon = (lonCliente - COORD_LOJA.lon) * Math.PI / 180;
    const a = Math.sin(dLat/2) * Math.sin(dLat/2) +
              Math.cos(COORD_LOJA.lat * Math.PI / 180) * Math.cos(latCliente * Math.PI / 180) *
              Math.sin(dLon/2) * Math.sin(dLon/2);
    const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
    const distanciaKm = R * c;
    
    const taxa = Math.max(4.00, distanciaKm * 1.40);
    return taxa.toFixed(2);
}


buildMenu();
setupScrollSpy();
